GUISubAnimScale = class("GUISubAnimScale", GUISubAnim)

function GUISubAnimScale:play()
    self.scaleStart = tonumber(self.config.scaleStart)
    self.scaleEnd = tonumber(self.config.scaleEnd)
    self.scale = self.scaleStart
    self.delta = (self.scaleEnd - self.scaleStart) / self.ticks
    LogUtil.log(string.format("GUISubAnimScale:play %s", tostring(self.delta)))
end

function GUISubAnimScale:update()
    --LogUtil.log("GUISubAnimScale:update")

    if not self.window or self.isEnd then
        return
    end

    self.scale = self.scale + self.delta
    if self.scale >= 0 then
        self.window:SetScale(VectorUtil.newVector3(self.scale, self.scale, self.scale))
        LogUtil.log("GUISubAnimScale:update " .. self.scale)
        self:checkEnd()
    end
end

function GUISubAnimScale:stop()
    --TODO
end

function GUISubAnimScale:onEnd()
    --TODO
end

function GUISubAnimScale:checkEnd()
    if self.delta == 0 then
        self.isEnd = true
    else
        if self.delta > 0 then
            self.isEnd = (self.scale >= self.scaleEnd)
        else
            self.isEnd = (self.scale <= self.scaleEnd)
        end
    end

    if self.isEnd then
        self.window:SetScale(VectorUtil.newVector3(self.scaleEnd, self.scaleEnd, self.scaleEnd))
    end
end

return GUISubAnimScale